function ModelPlayer:SaveTime()
    local lastOpenGame = LPlayerPrefs.SetOpenGameTime()
    if string.isempty(lastOpenGame) then
        LPlayerPrefs.SetOpenGameTime(os.time())
    else
        local isAcross = false
        local lastTime = tonumber(lastOpenGame)
        local curTime = os.time()
        local lastYear = tonumber(LUtil.OSDate("%Y", lastTime))
        local curYear = tonumber(LUtil.OSDate("%Y", curTime))
        if lastYear == curYear then
            -- 年份相同
            local lastNumWeek = tonumber(LUtil.OSDate("%W", lastTime))
            local curNumWeek = tonumber(LUtil.OSDate("%W", curTime))
            if lastNumWeek == curNumWeek then
                -- 第n个星期相同
                local lastWeek = tonumber(LUtil.OSDate("%w", lastTime))
                local curWeek = tonumber(LUtil.OSDate("%w", curTime))
                if curWeek == 0 then
                    -- 判断是否是同一天
                    if curWeek < lastWeek then
                        isAcross = true
                    end
                else
                    if curWeek > lastWeek then
                        isAcross = true
                    end
                end
            else
                isAcross = true
            end
        else
            isAcross = true
        end
        if isAcross then
            LPlayerPrefs.SetOpenGameTime(os.time())        -- 更新时间
            LPlayerPrefs.SetWndAlert("")
            gModelGeneral:SetAlertList(true)
        end
    end
end

