function ModelPlayer:SetPlayerInfo(data)
    self._playerName = data.name                        --玩家名称
    self._playerGender = data.gender                    --性别
    self._playerHead = data.head                        --头像Id
    self._playerHeadFrame = data.headFrame            --头像框Id
    self._playerFigure = data.figure                    --形象Id
    self._playerTitle = data.title                    --称号Id
    self._playerProvince = data.province                --省份
    self._playerCity = data.city                        --城市
    self._playerFightPower = data.fightPower            --战力
    self._playerLevel = tonumber(data.level)            --角色等级
    self._playerVipLevel = tonumber(data.vipLevel)    --VIP等级
    self._playerDiamond = data.diamond                --拥有钻石数量
    self._playerGold = data.gold                        --拥有金币数量
    self._playerExp = data.exp                        --拥有经验数量
    self._playerVipExp = data.vipExp                --拥有vip经验数量
    self._regTime = data.regTime                    --注册时间，单位秒
    self._curServerId = data.curServerId            --玩家初始服Id
    self._guildId = data.guildId                        --工会Id
    self._guildName = data.guildName                    --工会名称
    self._gradeLevel = data.gradeLevel                --玩家冒险评级等级
    self._gradeExp = data.gradeExp                    --玩家冒险评级经验
    self._lastLogoutTime = data.lastLogoutTime

    self._fightMaxPower = data.fightMaxPower --历史最高战力,只登陆发

    self._renameTime = data.renameTime              --取名次数
    local badge = data.badge
    self.badge = {}
    if badge then
        for i, v in ipairs(badge) do
            local arr = string.split(v, "=")
            self.badge[tonumber(arr[2])] = tonumber(arr[1])
        end
    end
    self.signature = data.signature                    --玩家个性签名
    self.age = data.age                                --年龄id

    self._disallowTalk = data.disallowTalk            --禁言状态（1=禁言）
    self._spaceName = data.spaceName                --空间名称
    local tag = data.tag
    local tags = {}
    if tag then
        for i, v in ipairs(tag) do
            local arr = string.split(v, "=")
            tags[tonumber(arr[2])] = tonumber(arr[1])
        end
    end
    self._tag = tags                                --标签
    self.backGround = data.backGround                --背景底框
    self.bubble = data.bubble                        --聊天气泡
    self.chargeMoney = data.chargeMoney                --累计充值金额
    self.ipCountry = data.ipCountry
    self.ipProvince = data.ipProvince
    self.firstChargeTime = data.firstChargeTime                --首次充值时间,秒
    self.leastChargeTime = data.leastChargeTime                --最后充值时间,秒
    self.firstChargeMoney = data.firstChargeMoney            --首单充值金额
    self.firstChargeTotal = data.firstChargeTotal            --首日充值总和
    self.mainCitySkin = data.mainCitySkin
    self.shieldInfo = data.shieldInfo                        --屏蔽信息 ， 用|号分割 ，屏蔽Vip显示|屏蔽聊天称号显示 0标识不屏蔽，1标识屏蔽
    --
    --local servername = self:GetServerName()
    --printInfoN("servrName "..servername)
    self:CheckNeedTranslateResType()
end

