--推送玩家信息变化
function ModelPlayer:OnPlayerChangeResp(pb)
    local oldVipLevel = self._playerVipLevel
    local oldLevel = self._playerLevel
    local oldChargeMoney = self.chargeMoney
    local oldGuildId = self._guildId
    local oldPlayerFigure = self._playerFigure
    local oldMainCitySkin = self.mainCitySkin

    self:SetPlayerInfo(pb.player)
    gLGameLogin:CheckOpenSex(self._playerLevel)

    local newVipLevel = self._playerVipLevel
    if oldVipLevel ~= newVipLevel then


        gModelWndPop:TryOpenPopWnd("UIHuiY")

        FireEvent(EventNames.PLAYER_VIP_LEVEL_CHANGE, oldVipLevel, newVipLevel)
        FireEvent(EventNames.ON_DREAM_FOUNTAIN)
        gLSdkImpl:CallMethod(LSdkMethod.OnVipLvUp)
    end

    local newLevel = self._playerLevel
    if oldLevel ~= newLevel then

    end

    if oldPlayerFigure ~= self._playerFigure then
        FireEvent(EventNames.ON_SPACE_PLAY_FIGURE_CHANGE)
    end

    if (oldChargeMoney ~= self.chargeMoney) then
        FireEvent(EventNames.ON_CHARGE_MONEY_CHANGE, oldChargeMoney, self.chargeMoney)
    end

    if oldMainCitySkin ~= self.mainCitySkin then
        FireEvent(EventNames.MAIN_CITY_SKIN_CHANGE)
    end
end

function ModelPlayer:onPlayerLvChange(data)

    local oldLevel = data.oldLevel
    local newLevel = data.newLevel
    if oldLevel == newLevel then
        return
    end

    if gModelBattle:IsReqMainResult() then
        return
    end

    local stageLimit = GameTable.MainInstanceConfigRef["levelUpTips"] or 0
    local curStage = gModelInstance:GetCurMissionCfg().refId
    if curStage > stageLimit then
        local para = {
            oldLv = oldLevel,
            newLv = newLevel,
        }
        if (oldLevel ~= 3 or newLevel ~= 4) then
            gModelBattle:OpenAccountRelaWnd("UILvUp", para)
        end
    end

    local showFormationUpdate = GameTable.SnakeRoleConfigRef["showFormationUpdate"]
    if showFormationUpdate and not string.isempty(showFormationUpdate) then
        local para = string.split(showFormationUpdate, ";")
        for _, v in ipairs(para) do
            if tonumber(v) == newLevel then
                self.updateShowFormation = true
                gModelPlayer:OnGetFormationShowReq(gModelPlayer:GetPlayerId(), LCombatTypeConst.COMBAT_MAIN)
            end
        end
    end

    gModelGuide:SetWaitGuideByLv(oldLevel, newLevel)

    gModelInstance:OnPlayerInstanceReq()

    gLSdkImpl:CallMethod(LSdkMethod.OnPlayerLvUp)
    FireEvent(EventNames.ON_PLAYER_LEVEL_CHANGE, oldLevel, newLevel)
end

