function ModelPlayer:OnGetFormationShowReq(targetId, formationType, teamIndex)
    if not targetId then
        return
    end
    local pb = LProtoHelper.CreateProto(LProtoIds.GetFormationShowReq)
    pb.formationType = formationType or LCombatTypeConst.COMBAT_SHOW_BATTLE
    pb.playerId = self:GetPlayerId()
    pb.targetId = targetId
    if teamIndex then
        pb.teamIndex = teamIndex
    end
    SendMessage(pb, LProtoIds.GetFormationShowReq)
end

