    local pb = LProtoHelper.CreateProto(LProtoIds.PersonaliseChangeReq)
    pb.type = type                                        --信息类型： 1.头像，2.头像框，3.称号 4.形象 5.徽章 6.标签 7.个性背景底框8.气泡设置

