function ModelPlayer:OnPersonaliseInfoResp(pb)
    --个性化信息请求返回
    local type = pb.type                            --信息类型： 1.头像，2.头像框，3.称号 4.形象 5.徽章 6.标签 7.个性背景底框8.气泡设置
    local info = self._personaliseInfo[type]
    info = {}
    for i, v in ipairs(pb.info) do
        local data = StructPersonaliseInfo:New()
        data:CreateByPb(v)
        info[data.refId] = data
    end
    self._personaliseInfo[type] = info

    self._timer:TimerRemoveByKey("key" .. type)
    local maxTime = 0
    local time = GetTimestamp()
    for i, v in pairs(info) do
        local expireTime = tonumber(v.expireTime) / 1000
        if (expireTime > 0) then
            local createTime = tonumber(v.createTime) / 1000
            local asOfTime = createTime + expireTime
            local countTime = asOfTime - time
            if (countTime > 0 and (maxTime > countTime or maxTime == 0)) then
                maxTime = countTime
            end
        end
    end
    if (maxTime > 0) then
        self._timer:TimerCreate("key" .. type, function(...)
            self:OnCountDown(...)
        end, maxTime, false, 1)
    end
end

function ModelPlayer:OnCountDown(key)
    self._timer:TimerRemoveByKey(key)
    local type = string.match(key, "%d+")
    self:OnPersonaliseInfoReq(tonumber(type))
end

