function ModelPlayer:InAccoutBindingReward(refId)
    if not refId then
        --兼容旧调用
        refId = 1
    end

    local checkNum = bit.lshift(1, refId)

    if not self._realNameData then
        self._realNameData = {}
    end
    if not self._realNameData.accoutBindingReward then
        self._realNameData.accoutBindingReward = 0
    end
    
    checkNum = bit.band(checkNum, self._realNameData.accoutBindingReward)
    return checkNum > 0
end

