function ModelPlayer:GetRolePlayerHeadListByType(type)
    local list = {}
    for i, v in pairs(GameTable.SnakeRolePlayerHeadRef) do

        if not gModelFunctionOpen:CheckRefDisable(ModelFunctionOpen.ROLEPALYERHEAD, v.refId) then
            if (v.type == type and v.uiShow == 1) then
                list[i] = v
            end
        end

    end
    if type == ModelPlayerSpace.ROLE_MEDAL then
        local curSeasonId = gModelCrossGrading:GetSeasonId()
        local curRefId = curSeasonId + ModelPlayer.SEASON_REFID_BASE
        local isHave = false
        local type5List = self:GetPersonaliseInfo(type) or {}
        for k, v in pairs(type5List) do
            local isRankType = self:IsRoleCrossGradingRankType(k)
            if isRankType then
                local ref = self:GetRolePlayerHeadRefByRefId(k)
                if ref then
                    if ref.type == type then
                        if curRefId == k then
                            isHave = true
                        end
                        list[k] = ref
                    end
                end
            end
        end
        if not isHave then
            printInfoNR("=== 赛季还没有结算")
            local ref = self:GetRolePlayerHeadRefByRefId(curRefId)
            if ref then
                if ref.type == type then
                    list[curRefId] = ref
                end
            end
        end
    end
    return list
end

function ModelPlayer:IsRoleCrossGradingRankType(refId)
    return refId >= self._minNum and refId <= self._maxNum
end

function ModelPlayer:GetRankSeasonStr(refId)
    local season = 0
    local seasonStr = ""
    local baseNum = ModelPlayer.SEASON_REFID_BASE
    refId = tonumber(refId)
    local isRankRefId = self:IsRoleCrossGradingRankType(refId)
    if isRankRefId and refId / baseNum > 0 then
        season = refId % baseNum
    end
    seasonStr = LUtil.FormatPowerNumSpriteText(season)
    return seasonStr
end

