function ModelPlayer:GetAttributes(attributesStr)
    local attributesList = {}
    if not string.isempty(attributesStr) then
        local stringList = string.split(attributesStr, ",") or {}
        for i, v in ipairs(stringList) do
            local valueList = string.split(v, "=") or {}
            local number = {}
            for c, s in ipairs(valueList) do
                table.insert(number, tonumber(s))
            end
            table.insert(attributesList, number)
        end
    end
    return attributesList
end

