function ModelPlayer:GetNewLevel(oldLv, oldExp, totalExp)
    local level = oldLv
    local exp = oldExp
    while totalExp > 0 do
        local curLevelExpNeed = self:GetLevelExpNeed(level)
        if curLevelExpNeed <= 0 then
            break
        end
        local consume = curLevelExpNeed - exp

        if consume <= 0 then
            break
        end

        if totalExp > consume then
            totalExp = totalExp - consume
            level = level + 1
            exp = 0
        elseif totalExp == consume then
            level = level + 1
            break
        else
            break
        end
    end

    return level
end

