--获取一个当前地区的假名
function ModelPlayer:GetFakeReName(needRandomseed)
    if needRandomseed == nil then
        needRandomseed = true
    end

    if needRandomseed then
        math.randomseed(tostring(os.time()):reverse():sub(1, 7))
    end

    local nameFlag = gLGameLanguage:GetRandomNameFlag()

    local randomIndex
    local ref
    local maxNum = #GameTable.RandomNamebaseRef or 1000

    for i = 1, 20 do
        randomIndex = self:GerFakeRandomNum(1, maxNum)
        ref = GameTable.RandomNamebaseRef[randomIndex]
        if ref.position == 1 then
            break
        end
    end

    if not ref then
        randomIndex = self:GerFakeRandomNum(1, 100)
        ref = GameTable.RandomNamebaseRef[randomIndex]
    end

    local firstName = ref[nameFlag]
    if nameFlag == "zhcn" then
        for i = 1, 20 do
            randomIndex = self:GerFakeRandomNum(1, maxNum)
            ref = GameTable.RandomNamebaseRef[randomIndex]
            if ref and ref.position == 3 then
                break
            end
        end

        if not ref then
            randomIndex = self:GerFakeRandomNum(250, 500)
            ref = GameTable.RandomNamebaseRef[randomIndex]
        end
        local secondName = ref and ref[nameFlag] or ""
        return firstName .. secondName
    else
        return firstName
    end
end

function ModelPlayer:GerFakeRandomNum(firstNum, maxNum)
    return math.random(firstNum, maxNum)
end

