function ModelPlayer:GetChargeMoney()
    return self.chargeMoney
end

function ModelPlayer:CheckNeedTranslateResType()
    --LogWarn("-----资源类型检测 充值检测开始")
    if not gLGameLanguage:IsChinaRegion() then return end

    local isBlack = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.IsBlacklist)
    if isBlack then return end

    local openRecharge = self:GetNeedCheckResTypeNum()
    if not openRecharge then
        --LogWarn("-----资源类型检测 获取不到对应的充值金额")
        return 
    end
    
    if openRecharge == -1 then
        --LogWarn("-----资源类型检测 openRecharge == -1")
        --- app 需要强制改成3，微小暂定
        if CS.IsWebGL() and LWxHelper.IsMiniGamePlatform() then
        else
            LPlayerPrefs.GMSetLocalization(3)
        end
        return
    end

    openRecharge = openRecharge * 100
    local chargeMoney = self:GetChargeMoney() or 0
    if LOG_INFO_ENABLED then
        printInfoN("归因状态 openRecharge：" .. openRecharge)
    end
    --LogWarn(string.replace("-----资源类型检测 已充值：#a1#,达成条件需充值：#a2#",chargeMoney,openRecharge))
    --- 这个累计充值6元是实际充值金额，不包含代金券
    if chargeMoney >= openRecharge then
        LPlayerPrefs.GMSetLocalization(1)
    end
end

function ModelPlayer:GetNeedCheckResTypeNum()
    local initNeedCheckResTypeMap = self._initNeedCheckResTypeMap
    if not initNeedCheckResTypeMap then
        initNeedCheckResTypeMap = {}
        local openTypeStr
        if CS.IsWebGL() and LWxHelper.IsMiniGamePlatform() then
            openTypeStr = GameTable.InnerActivityConfigRef["openRechargeWx"]
        else
            openTypeStr = GameTable.InnerActivityConfigRef["openRecharge"]
        end
        if not string.isempty(openTypeStr) then
            local openTypeStrs = string.split(openTypeStr,"|")
            for i,v in ipairs(openTypeStrs) do
                v = string.split(v,"=")
                local tPackId = 0
                if #v > 2 then
                    tPackId = checknumber(v[3])
                end
                local packageMap = initNeedCheckResTypeMap[tPackId]
                if not packageMap then
                    packageMap = {}
                    initNeedCheckResTypeMap[tPackId] = packageMap
                end
                packageMap[checknumber(v[1])] = checknumber(v[2])
            end
        end
        self._initNeedCheckResTypeMap = initNeedCheckResTypeMap
    end
    local packageId = gModelActivity:GetPackageId()
    local tpackageMap = initNeedCheckResTypeMap[packageId]
    if not tpackageMap then
        --- 没有配置包 id ，默认使用0
        tpackageMap = initNeedCheckResTypeMap[0]
    end
    local resType = LPlayerPrefs.GetLocalization()
    if LOG_INFO_ENABLED then
        printInfoN("归因状态 resType = " .. resType)
    end
    return resType and tpackageMap[resType]
end

