    gModelDYFeed:CheckFeedSubscribeOffline()
end
--endregion

function ModelPlayer:CheckRolePlayerHeadIsOpen(activation,curTime)
    if string.isempty(activation) then return true end
    local activations = string.split(activation,"=")
    local activationType = checknumber(activations[1])
    if (activationType == 1 or activationType == 102) and activations[2] then
        local activationHero = checknumber(activations[2])
        if activationHero and activationHero > 0 then
            local heroRef = gModelHero:GetHeroRef(activationHero)
            if heroRef then
                curTime = curTime or GetTimestamp()
                if not gModelHero:GetHeroActShowState(heroRef.refId,curTime) then
                    return false
                end
            end
        end
    end
    return true
end


