--清理工作
--停止计时器之类的
function ModelPlayer:OnModelClear()
    if self._delayTimeSdkUploadCall then
        LxTimer.DelayTimeStop(self._delayTimeSdkUploadCall)
    end
    local timer = self._timer
    if timer then
        timer:Destroy()
        self._timer = nil
    end
end
return ModelPlayer